  const getIcon = (item: FileSystemItem) => {
    if (item.type === FileType.FOLDER) return <Folder className="w-12 h-12 text-blue-400 mb-2 fill-blue-400/20" />;
    if (item.name.endsWith('.png')) return <ImageIcon className="w-12 h-12 text-purple-400 mb-2" />;
    if (item.name.endsWith('.pdf')) return <FileText className="w-12 h-12 text-red-400 mb-2" />;
    return <FileCode className="w-12 h-12 text-gray-400 mb-2" />;
  };

  return (
    <div className="flex h-full bg-white dark:bg-gray-900 text-gray-800 dark:text-gray-100">
      {/* Sidebar */}
      <div className="w-48 bg-gray-50/50 dark:bg-gray-800/50 border-r border-gray-200 dark:border-gray-700 p-4 backdrop-blur-md hidden sm:block">
        <div className="text-xs font-semibold text-gray-400 mb-2 uppercase tracking-wider">Favorites</div>
        <ul className="space-y-1">
          {['Desktop', 'Experience', 'Projects', 'Playground'].map((name) => {
             // Basic implementation: find folder by name for demo
             const folder = Object.values(files).find(f => f.name === name && f.type === FileType.FOLDER);
             return (
               <li 
                 key={name}
                 className={`flex items-center gap-2 px-2 py-1.5 rounded-md cursor-pointer transition-colors ${folder?.id === currentId ? 'bg-blue-500/10 text-blue-600 dark:text-blue-400' : 'hover:bg-gray-100 dark:hover:bg-gray-700'}`}
                 onClick={() => folder && setCurrentId(folder.id)}
               >
                 <Folder size={16} className={folder?.id === currentId ? 'fill-blue-500' : ''} />
                 <span className="text-sm">{name}</span>
               </li>
             );
