            disabled={!currentFolder.parentId || currentFolder.id === 'desktop'}
            className="p-1.5 rounded-md hover:bg-gray-100 dark:hover:bg-gray-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
          >
            <ArrowLeft size={18} />
