import React, { useState, useRef, useEffect } from 'react';
import { FileSystemItem } from '../../types';

interface TerminalProps {
  files: Record<string, FileSystemItem>;
  onOpenApp: (appId: string, param?: string) => void;
}

const Terminal: React.FC<TerminalProps> = ({ files, onOpenApp }) => {
  const [history, setHistory] = useState<string[]>(['Welcome to PortfolioOS v1.0.0', 'Type "help" to see available commands.']);
  const [input, setInput] = useState('');
  const [commandHistory, setCommandHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const bottomRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
    inputRef.current?.focus();
  }, [history]);

  const handleCommand = (cmd: string) => {
    const trimmed = cmd.trim();
    if (!trimmed) return;

    const [command, ...args] = trimmed.split(' ');
    setCommandHistory(prev => [trimmed, ...prev]);
    setHistoryIndex(-1);

    const output = [`➜  ~ ${trimmed}`];

    switch (command.toLowerCase()) {
      case 'help':
        output.push(
          'Available commands:',
          '  help        - Show this help message',
          '  ls          - List directory contents',
          '  cat <file>  - Display file content',
          '  clear       - Clear terminal',
          '  whoami      - Display user info',
          '  open <app>  - Open an application (e.g., open mail)',
          '  email       - Check email',
          '  minesweeper - Play a game',
          '  cv          - View Resume'
        );
        break;
      case 'ls':
        // Simplified ls - just listing desktop
        const desktop = files['desktop'];
        if (desktop && desktop.children) {
          const names = desktop.children.map(cid => files[cid]?.name).filter(Boolean).join('  ');
          output.push(names);
        }
        break;
      case 'whoami':
        output.push('visitor@portfolio-os');
        break;
      case 'clear':
        setHistory([]);
        setInput('');
        return;
      case 'cv':
        onOpenApp('pdf_viewer', 'file_cv');
        output.push('Opening CV...');
        break;
      case 'email':
        onOpenApp('email');
        output.push('Opening Mail Client...');
        break;
      case 'minesweeper':
        onOpenApp('minesweeper');
        output.push('Starting Minesweeper...');
        break;
      case 'easter_eggs':
        output.push('🥚 You found one! Try dragging the "Minesweeper" icon to the Trash... just kidding, don\'t do that.');
        break;
      case 'cat':
        if (args.length === 0) {
          output.push('Usage: cat <filename>');
        } else {
          // Flatten search for simplicity
          const fileName = args[0];
          const foundFile = Object.values(files).find(f => f.name === fileName && f.content);
          if (foundFile) {
             output.push(foundFile.content || '');
          } else {
            output.push(`cat: ${fileName}: No such file or directory`);
          }
        }
        break;
      default:
        output.push(`command not found: ${command}`);
    }

    setHistory(prev => [...prev, ...output]);
    setInput('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleCommand(input);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (historyIndex < commandHistory.length - 1) {
        const newIndex = historyIndex + 1;
        setHistoryIndex(newIndex);
        setInput(commandHistory[newIndex]);
      }
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      if (historyIndex > 0) {
        const newIndex = historyIndex - 1;
        setHistoryIndex(newIndex);
        setInput(commandHistory[newIndex]);
      } else {
        setHistoryIndex(-1);
        setInput('');
      }
    }
  };

  return (
    <div 
      className="h-full bg-[#1e1e1e] text-[#d4d4d4] font-mono text-sm p-4 overflow-auto"
      onClick={() => inputRef.current?.focus()}
    >
      {history.map((line, i) => (
        <div key={i} className="whitespace-pre-wrap mb-1 leading-relaxed">{line}</div>
      ))}
      <div className="flex">
        <span className="text-green-500 mr-2">➜</span>
        <span className="text-blue-400 mr-2">~</span>
        <input
          ref={inputRef}
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          className="flex-1 bg-transparent outline-none border-none text-[#d4d4d4]"
          autoComplete="off"
          autoFocus
        />
      </div>
      <div ref={bottomRef} />
    </div>
  );
};

export default Terminal;

import React from 'react';
import { FileSystemItem } from '../../types';

interface TextEditorProps {
  file: FileSystemItem | null;
}

const TextEditor: React.FC<TextEditorProps> = ({ file }) => {
  if (!file) return <div className="p-4 text-gray-500">No file open</div>;

  return (
    <div className="h-full flex flex-col bg-white dark:bg-gray-900 text-gray-800 dark:text-gray-100 font-mono">
       <div className="p-8 max-w-2xl mx-auto w-full overflow-auto">
         {file.name.endsWith('.md') ? (
            <div className="prose dark:prose-invert">
              {file.content?.split('\n').map((line, i) => {
                if (line.startsWith('# ')) return <h1 key={i} className="text-2xl font-bold mb-4">{line.replace('# ', '')}</h1>;
                if (line.startsWith('## ')) return <h2 key={i} className="text-xl font-bold mb-3">{line.replace('## ', '')}</h2>;
                if (line.startsWith('- ')) return <li key={i} className="ml-4">{line.replace('- ', '')}</li>;
                return <p key={i} className="mb-2 min-h-[1em]">{line}</p>;
              })}
            </div>
         ) : (
           <pre className="whitespace-pre-wrap font-mono text-sm leading-relaxed">{file.content}</pre>
         )}
       </div>
    </div>
  );
};

export default TextEditor;

import React, { useState, useEffect } from 'react';
import { Bomb, Flag } from 'lucide-react';

interface Cell {
  x: number;
  y: number;
  isMine: boolean;
  isRevealed: boolean;
  isFlagged: boolean;
  neighborMines: number;
}

const BOARD_SIZE = 9;
const MINES_COUNT = 10;

const Minesweeper: React.FC = () => {
  const [board, setBoard] = useState<Cell[][]>([]);
  const [gameOver, setGameOver] = useState(false);
  const [win, setWin] = useState(false);
  const [flags, setFlags] = useState(MINES_COUNT);
  const [time, setTime] = useState(0);
  const [started, setStarted] = useState(false);

  useEffect(() => {
    initGame();
  }, []);

  useEffect(() => {
    let interval: any;
    if (started && !gameOver && !win) {
      interval = setInterval(() => setTime(t => t + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [started, gameOver, win]);

  const initGame = () => {
    const newBoard: Cell[][] = Array(BOARD_SIZE).fill(null).map((_, y) => 
      Array(BOARD_SIZE).fill(null).map((_, x) => ({
        x, y, isMine: false, isRevealed: false, isFlagged: false, neighborMines: 0
      }))
    );

    // Place mines
    let minesPlaced = 0;
    while (minesPlaced < MINES_COUNT) {
      const x = Math.floor(Math.random() * BOARD_SIZE);
      const y = Math.floor(Math.random() * BOARD_SIZE);
      if (!newBoard[y][x].isMine) {
        newBoard[y][x].isMine = true;
        minesPlaced++;
      }
    }

    // Calculate neighbors
    for (let y = 0; y < BOARD_SIZE; y++) {
      for (let x = 0; x < BOARD_SIZE; x++) {
        if (!newBoard[y][x].isMine) {
          let count = 0;
          for (let dy = -1; dy <= 1; dy++) {
            for (let dx = -1; dx <= 1; dx++) {
              if (y + dy >= 0 && y + dy < BOARD_SIZE && x + dx >= 0 && x + dx < BOARD_SIZE) {
                if (newBoard[y + dy][x + dx].isMine) count++;
              }
            }
          }
          newBoard[y][x].neighborMines = count;
        }
      }
    }

    setBoard(newBoard);
    setGameOver(false);
    setWin(false);
    setFlags(MINES_COUNT);
    setTime(0);
    setStarted(false);
  };

  const revealCell = (x: number, y: number) => {
    if (gameOver || win || board[y][x].isFlagged || board[y][x].isRevealed) return;

    if (!started) setStarted(true);

    const newBoard = [...board];
    const cell = newBoard[y][x];

    if (cell.isMine) {
      cell.isRevealed = true;
      setBoard(newBoard);
      setGameOver(true);
      return;
    }

    const floodFill = (cx: number, cy: number) => {
      if (cx < 0 || cx >= BOARD_SIZE || cy < 0 || cy >= BOARD_SIZE || newBoard[cy][cx].isRevealed || newBoard[cy][cx].isFlagged) return;

      newBoard[cy][cx].isRevealed = true;

      if (newBoard[cy][cx].neighborMines === 0) {
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
             floodFill(cx + dx, cy + dy);
          }
        }
      }
    };

    floodFill(x, y);
    setBoard(newBoard);

    // Check win
    const unrevealedSafeCells = newBoard.flat().filter(c => !c.isMine && !c.isRevealed).length;
    if (unrevealedSafeCells === 0) {
      setWin(true);
    }
  };

  const toggleFlag = (e: React.MouseEvent, x: number, y: number) => {
    e.preventDefault();
    if (gameOver || win || board[y][x].isRevealed) return;

    const newBoard = [...board];
    if (newBoard[y][x].isFlagged) {
      newBoard[y][x].isFlagged = false;
      setFlags(f => f + 1);
    } else {
      if (flags > 0) {
        newBoard[y][x].isFlagged = true;
        setFlags(f => f - 1);
      }
    }
    setBoard(newBoard);
  };

  return (
    <div className="h-full flex flex-col items-center justify-center bg-[#c0c0c0] p-4 select-none font-mono border-4 border-white border-r-gray-500 border-b-gray-500">
      <div className="w-full flex justify-between items-center mb-4 bg-[#c0c0c0] border-2 border-gray-500 border-r-white border-b-white p-2">
        <div className="bg-black text-red-600 px-2 text-2xl font-bold">{String(flags).padStart(3, '0')}</div>
        <button onClick={initGame} className="text-2xl p-1 active:translate-y-[1px] border-2 border-white border-r-gray-500 border-b-gray-500 active:border-gray-500 active:border-r-white active:border-b-white bg-[#c0c0c0]">
          {gameOver ? '😵' : win ? '😎' : '🙂'}
        </button>
        <div className="bg-black text-red-600 px-2 text-2xl font-bold">{String(time).padStart(3, '0')}</div>
      </div>

      <div 
        className="grid gap-[2px] bg-gray-500 p-[2px] border-4 border-gray-500 border-r-white border-b-white"
        style={{ gridTemplateColumns: `repeat(${BOARD_SIZE}, 1fr)` }}
      >
        {board.map((row, y) => row.map((cell, x) => (
          <div
            key={`${x}-${y}`}
            className={`w-8 h-8 flex items-center justify-center text-sm font-bold cursor-pointer
              ${cell.isRevealed 
                ? 'bg-[#c0c0c0] border border-gray-400' 
                : 'bg-[#c0c0c0] border-2 border-white border-r-gray-500 border-b-gray-500 hover:brightness-105 active:border-gray-500 active:border-r-white active:border-b-white'
              }
              ${cell.isRevealed && cell.isMine ? 'bg-red-500' : ''}
            `}
            onClick={() => revealCell(x, y)}
            onContextMenu={(e) => toggleFlag(e, x, y)}
          >
            {cell.isRevealed ? (
              cell.isMine ? <Bomb size={16} /> : cell.neighborMines > 0 ? (
                <span style={{ color: ['blue', 'green', 'red', 'darkblue', 'brown', 'cyan', 'black', 'gray'][cell.neighborMines - 1] }}>
                  {cell.neighborMines}
                </span>
              ) : ''
            ) : (
              cell.isFlagged ? <Flag size={14} className="text-red-600 fill-red-600" /> : ''
            )}
          </div>
        )))}
      </div>
    </div>
  );
};

