import React, { useRef } from 'react';
import { FileSystemItem, FileType, AppID } from '../../types';
import { Folder, FileText, Image as ImageIcon, Trash2, Mail, Terminal, Gamepad2, FileCode } from 'lucide-react';

interface DesktopProps {
  files: Record<string, FileSystemItem>;
  selectedIds: string[];
  onSelect: (id: string, multi: boolean) => void;
  onOpen: (item: FileSystemItem) => void;
}

const Desktop: React.FC<DesktopProps> = ({ files, selectedIds, onSelect, onOpen }) => {
  const desktopItems = files['desktop'].children?.map(id => files[id]) || [];
  const containerRef = useRef<HTMLDivElement>(null);

  const getIcon = (item: FileSystemItem) => {
    // Custom App Icons
    if (item.appId === AppID.EMAIL) return <Mail className="w-12 h-12 text-blue-500 drop-shadow-md" />;
    if (item.appId === AppID.TERMINAL) return <Terminal className="w-12 h-12 text-gray-700 dark:text-gray-300 drop-shadow-md" />;
    if (item.appId === AppID.MINESWEEPER) return <Gamepad2 className="w-12 h-12 text-purple-500 drop-shadow-md" />;
    if (item.appId === AppID.TRASH) return <Trash2 className="w-12 h-12 text-gray-500 drop-shadow-md" />;

    // File Types
    if (item.type === FileType.FOLDER) return <Folder className="w-12 h-12 text-blue-400 fill-blue-400/20 drop-shadow-md" />;
    if (item.name.endsWith('.pdf')) return <FileText className="w-12 h-12 text-red-400 drop-shadow-md" />;
    if (item.name.endsWith('.png')) return <ImageIcon className="w-12 h-12 text-purple-400 drop-shadow-md" />;
    if (item.name.endsWith('.txt')) return <FileText className="w-12 h-12 text-gray-400 drop-shadow-md" />;

    return <FileCode className="w-12 h-12 text-gray-400" />;
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    if (e.target === containerRef.current) {
      onSelect('', false);
    }
  };

  return (
    <div 
      ref={containerRef}
      className="absolute inset-0 z-0 p-4 grid grid-flow-col grid-rows-[repeat(auto-fill,100px)] gap-4 content-start items-start justify-items-start"
      onPointerDown={handlePointerDown}
    >
      {desktopItems.map(item => {
         const isSelected = selectedIds.includes(item.id);
         return (
           <div
             key={item.id}
             className={`w-24 h-24 flex flex-col items-center justify-center gap-1 rounded-md border border-transparent transition-all duration-200 group
               ${isSelected ? 'bg-white/20 border-white/30 backdrop-blur-sm shadow-sm' : 'hover:bg-white/10'}
             `}
             onPointerDown={(e) => {
               e.stopPropagation();
               onSelect(item.id, e.metaKey || e.ctrlKey);
             }}
             onDoubleClick={(e) => {
               e.stopPropagation();
               onOpen(item);
             }}
           >
             <div className="transition-transform group-hover:scale-105">
               {getIcon(item)}
             </div>
             <span 
               className={`text-xs font-medium text-center px-2 py-0.5 rounded
                 ${isSelected ? 'bg-blue-600 text-white' : 'text-white drop-shadow-md shadow-black'}
               `}
               style={{ textShadow: isSelected ? 'none' : '0 1px 2px rgba(0,0,0,0.5)' }}
             >
               {item.name}
             </span>
           </div>
         );
      })}
    </div>
  );
};

