import React, { useRef, useState, useEffect } from 'react';
import { motion, useDragControls } from 'framer-motion';
import { X, Minus, Maximize2 } from 'lucide-react';
import { WindowState } from '../../types';

interface WindowProps {
  window: WindowState;
  isActive: boolean;
  onClose: (id: string) => void;
  onMinimize: (id: string) => void;
  onMaximize: (id: string) => void;
  onFocus: (id: string) => void;
  onResize: (id: string, width: number, height: number) => void;
  children: React.ReactNode;
}

const Window: React.FC<WindowProps> = ({ 
  window, 
  isActive, 
  onClose, 
  onMinimize, 
  onMaximize, 
  onFocus, 
  onResize,
  children 
}) => {
  const dragControls = useDragControls();
  const windowRef = useRef<HTMLDivElement>(null);
  const [isResizing, setIsResizing] = useState(false);

  const handleResizeStart = (e: React.PointerEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsResizing(true);
    onFocus(window.id);

    const startX = e.clientX;
    const startY = e.clientY;
    const startWidth = window.size.width;
    const startHeight = window.size.height;

    const handlePointerMove = (moveEvent: PointerEvent) => {
      const newWidth = Math.max(300, startWidth + (moveEvent.clientX - startX));
      const newHeight = Math.max(200, startHeight + (moveEvent.clientY - startY));
      onResize(window.id, newWidth, newHeight);
    };

    const handlePointerUp = () => {
      setIsResizing(false);
      document.removeEventListener('pointermove', handlePointerMove);
      document.removeEventListener('pointerup', handlePointerUp);
    };

    document.addEventListener('pointermove', handlePointerMove);
    document.addEventListener('pointerup', handlePointerUp);
  };

  return (
    <motion.div
      drag={!window.isMaximized && !isResizing}
      dragControls={dragControls}
      dragMomentum={false}
      dragElastic={0.05}
      initial={{ scale: 0.9, opacity: 0, y: 20 }}
      animate={{ 
        scale: window.isMinimized ? 0 : window.isMaximized ? 1 : 1, 
        opacity: window.isMinimized ? 0 : 1,
        y: window.isMinimized ? 200 : 0,
        x: window.isMaximized ? 0 : window.position.x,
        top: window.isMaximized ? 0 : window.position.y,
        width: window.isMaximized ? '100%' : window.size.width,
        height: window.isMaximized ? '100%' : window.size.height,
        borderRadius: window.isMaximized ? 0 : 12,
      }}
      transition={{ 
        type: "spring", 
        stiffness: 300, 
        damping: 30,
        // Disable layout animation during resize to prevent lag/jitter
        layout: { duration: isResizing ? 0 : 0.3 }
      }}
      className={`absolute flex flex-col overflow-hidden bg-white/80 dark:bg-gray-900/90 backdrop-blur-xl border border-white/20 shadow-2xl ${isActive ? 'z-50 ring-1 ring-black/5' : 'z-0'}`}
      style={{ 
        zIndex: window.zIndex,
        left: 0, // Controlled by motion.x
      }}
      onPointerDown={() => onFocus(window.id)}
      ref={windowRef}
    >
      {/* Title Bar */}
      <div 
        className="h-10 flex items-center justify-between px-4 select-none bg-gradient-to-b from-white/50 to-transparent dark:from-white/5 border-b border-gray-200/50 dark:border-gray-700/50 flex-shrink-0"
        onPointerDown={(e) => {
          dragControls.start(e);
          onFocus(window.id);
        }}
      >
        <div className="flex gap-2 group">
          <button onClick={(e) => { e.stopPropagation(); onClose(window.id); }} className="w-3 h-3 rounded-full bg-red-500 hover:bg-red-600 flex items-center justify-center transition-colors text-black/50 group-hover:text-black/80">
            <X size={8} className="opacity-0 group-hover:opacity-100" />
          </button>
          <button onClick={(e) => { e.stopPropagation(); onMinimize(window.id); }} className="w-3 h-3 rounded-full bg-yellow-400 hover:bg-yellow-500 flex items-center justify-center transition-colors text-black/50 group-hover:text-black/80">
            <Minus size={8} className="opacity-0 group-hover:opacity-100" />
          </button>
          <button onClick={(e) => { e.stopPropagation(); onMaximize(window.id); }} className="w-3 h-3 rounded-full bg-green-500 hover:bg-green-600 flex items-center justify-center transition-colors text-black/50 group-hover:text-black/80">
            <Maximize2 size={6} className="opacity-0 group-hover:opacity-100" />
          </button>
        </div>
        <span className="text-sm font-medium text-gray-700 dark:text-gray-200">{window.title}</span>
        <div className="w-12"></div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-auto relative">
        {children}
      </div>

      {/* Resize Handle */}
      {!window.isMaximized && (
        <div 
          className="absolute bottom-0 right-0 w-6 h-6 cursor-se-resize z-50 flex items-end justify-end p-1"
          onPointerDown={handleResizeStart}
        >
           {/* Visual handle indicator */}
           <svg width="8" height="8" viewBox="0 0 10 10" className="opacity-30">
              <path d="M10 10 L0 10 L10 0 Z" fill="currentColor" />
           </svg>
        </div>
      )}
    </motion.div>
  );
};

export default Window;

