interface DesktopProps {
  files: Record<string, FileSystemItem>;
  selectedIds: string[];
  onSelect: (id: string, multi: boolean) => void;
  onOpen: (item: FileSystemItem) => void;
}

const Desktop: React.FC<DesktopProps> = ({ files, selectedIds, onSelect, onOpen }) => {
  const desktopItems = files['desktop'].children?.map(id => files[id]) || [];
  const containerRef = useRef<HTMLDivElement>(null);

  const getIcon = (item: FileSystemItem) => {
    // Custom App Icons
    if (item.appId === AppID.EMAIL) return <Mail className="w-12 h-12 text-stone-500 drop-shadow-md" />;
    if (item.appId === AppID.TERMINAL) return <Terminal className="w-12 h-12 text-gray-700 dark:text-gray-300 drop-shadow-md" />;
    if (item.appId === AppID.MINESWEEPER) return <Gamepad2 className="w-12 h-12 text-stone-600 drop-shadow-md" />;
    if (item.appId === AppID.TRASH) return <Trash2 className="w-12 h-12 text-stone-400 drop-shadow-md" />;

    // File Types
    if (item.type === FileType.FOLDER) return <Folder className="w-12 h-12 text-stone-400 fill-stone-400/20 drop-shadow-md" />;
    if (item.name.endsWith('.pdf')) return <FileText className="w-12 h-12 text-stone-500 drop-shadow-md" />;
    if (item.name.endsWith('.png')) return <ImageIcon className="w-12 h-12 text-stone-500 drop-shadow-md" />;
    if (item.name.endsWith('.txt')) return <FileText className="w-12 h-12 text-stone-400 drop-shadow-md" />;

    return <FileCode className="w-12 h-12 text-stone-400" />;
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    if (e.target === containerRef.current) {
      onSelect('', false);
    }
  };

  return (
    <div 
      ref={containerRef}
      className="absolute inset-0 z-0 p-4 grid grid-flow-col grid-rows-[repeat(auto-fill,110px)] gap-2 content-start items-start justify-items-start"
      onPointerDown={handlePointerDown}
    >
      {desktopItems.map(item => {
         const isSelected = selectedIds.includes(item.id);
         return (
           <div
             key={item.id}
             className={`w-24 flex flex-col items-center justify-start gap-1 p-1 rounded-md border border-transparent transition-all duration-200 group
               ${isSelected ? 'bg-stone-500/30 border-stone-500/20 backdrop-blur-md shadow-sm' : 'hover:bg-white/10'}
             `}
             onPointerDown={(e) => {
               e.stopPropagation();
               onSelect(item.id, e.metaKey || e.ctrlKey);
             }}
             onDoubleClick={(e) => {
               e.stopPropagation();
               onOpen(item);
             }}
           >
             <div className="transition-transform group-hover:scale-105 shrink-0">
               {getIcon(item)}
             </div>
             <span 
               className={`text-xs font-medium text-center px-2 py-0.5 rounded w-full break-words leading-tight
                 ${isSelected ? 'bg-stone-600 text-white' : 'text-white drop-shadow-md shadow-black'}
               `}
               style={{ textShadow: isSelected ? 'none' : '0 1px 2px rgba(0,0,0,0.5)' }}
             >
               {item.name}
             </span>
           </div>
         );
      })}
    </div>
  );
};

