import React, { useState, useRef, useEffect } from 'react';
import { FileSystemItem } from '../../types';

interface TerminalProps {
  files: Record<string, FileSystemItem>;
  onOpenApp: (appId: string, param?: string) => void;
  onInteraction: (type: string, data?: any) => void;
}

const Terminal: React.FC<TerminalProps> = ({ files, onOpenApp, onInteraction }) => {
  const [history, setHistory] = useState<string[]>(['Welcome to PortfolioOS v1.0.0', 'Type "help" to see available commands.']);
  const [input, setInput] = useState('');
  const [commandHistory, setCommandHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const bottomRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
    inputRef.current?.focus();
  }, [history]);

  const handleCommand = (cmd: string) => {
    const trimmed = cmd.trim();
    if (!trimmed) return;

    // Report interaction for achievements
    onInteraction('terminal_command', trimmed);

    const [command, ...args] = trimmed.split(' ');
    setCommandHistory(prev => [trimmed, ...prev]);
    setHistoryIndex(-1);

    const output = [`➜  ~ ${trimmed}`];

    switch (command.toLowerCase()) {
      case 'help':
        onInteraction('terminal_help');
        output.push(
          'Available commands:',
          '  help        - Show this help message',
          '  ls          - List directory contents',
          '  cat <file>  - Display file content',
          '  clear       - Clear terminal',
          '  whoami      - Display user info',
          '  open <app>  - Open an application (e.g., open mail)',
          '  email       - Check email',
          '  minesweeper - Play a game',
          '  cv          - View Resume'
        );
        break;
      case 'ls':
        // Simplified ls - just listing desktop
        const desktop = files['desktop'];
        if (desktop && desktop.children) {
          const names = desktop.children.map(cid => files[cid]?.name).filter(Boolean).join('  ');
          output.push(names);
        }
        break;
      case 'whoami':
        output.push('visitor@portfolio-os');
        break;
      case 'clear':
        setHistory([]);
        setInput('');
        return;
      case 'cv':
        onOpenApp('pdf_viewer', 'file_cv');
        output.push('Opening CV...');
        break;
      case 'email':
        onOpenApp('email');
        output.push('Opening Mail Client...');
        break;
      case 'minesweeper':
        onOpenApp('minesweeper');
        output.push('Starting Minesweeper...');
        break;
      case 'easter_eggs':
        output.push('🥚 You found one! Try dragging the "Minesweeper" icon to the Trash... just kidding, don\'t do that.');
        break;
      case 'cat':
        if (args.length === 0) {
          output.push('Usage: cat <filename>');
        } else {
          // Flatten search for simplicity
          const fileName = args[0];
          const foundFile = Object.values(files).find(f => f.name === fileName && f.content);
          if (foundFile) {
             output.push(foundFile.content || '');
          } else {
            output.push(`cat: ${fileName}: No such file or directory`);
          }
        }
        break;
      default:
        output.push(`command not found: ${command}`);
    }

    setHistory(prev => [...prev, ...output]);
    setInput('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleCommand(input);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (historyIndex < commandHistory.length - 1) {
        const newIndex = historyIndex + 1;
        setHistoryIndex(newIndex);
        setInput(commandHistory[newIndex]);
      }
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      if (historyIndex > 0) {
        const newIndex = historyIndex - 1;
        setHistoryIndex(newIndex);
        setInput(commandHistory[newIndex]);
      } else {
        setHistoryIndex(-1);
        setInput('');
      }
    }
  };

  return (
    <div 
      className="h-full bg-[#1e1e1e] text-[#d4d4d4] font-mono text-sm p-4 overflow-auto"
      onClick={() => inputRef.current?.focus()}
    >
      {history.map((line, i) => (
        <div key={i} className="whitespace-pre-wrap mb-1 leading-relaxed">{line}</div>
      ))}
      <div className="flex">
        <span className="text-green-500 mr-2">➜</span>
        <span className="text-blue-400 mr-2">~</span>
        <input
          ref={inputRef}
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          className="flex-1 bg-transparent outline-none border-none text-[#d4d4d4]"
          autoComplete="off"
          autoFocus
        />
      </div>
      <div ref={bottomRef} />
    </div>
  );
};

export default Terminal;

import React, { useState, useEffect } from 'react';
import { Bomb, Flag } from 'lucide-react';

interface MinesweeperProps {
  onInteraction: (type: string, data?: any) => void;
}

interface Cell {
  x: number;
  y: number;
  isMine: boolean;
  isRevealed: boolean;
  isFlagged: boolean;
  neighborMines: number;
}

const BOARD_SIZE = 9;
const MINES_COUNT = 10;

const Minesweeper: React.FC<MinesweeperProps> = ({ onInteraction }) => {
  const [board, setBoard] = useState<Cell[][]>([]);
  const [gameOver, setGameOver] = useState(false);
  const [win, setWin] = useState(false);
  const [flags, setFlags] = useState(MINES_COUNT);
  const [time, setTime] = useState(0);
  const [started, setStarted] = useState(false);

  useEffect(() => {
    initGame();
  }, []);

  useEffect(() => {
    let interval: any;
    if (started && !gameOver && !win) {
      interval = setInterval(() => setTime(t => t + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [started, gameOver, win]);

  useEffect(() => {
    if (win) {
      onInteraction('minesweeper_win');
    }
    if (gameOver && !win) {
      onInteraction('minesweeper_loss');
    }
  }, [win, gameOver]);

  const initGame = () => {
    // If restarting (started is true), report restart for "Just One More" achievement
    if (started) {
      onInteraction('game_restart', 'minesweeper');
    }

    const newBoard: Cell[][] = Array(BOARD_SIZE).fill(null).map((_, y) => 
      Array(BOARD_SIZE).fill(null).map((_, x) => ({
        x, y, isMine: false, isRevealed: false, isFlagged: false, neighborMines: 0
      }))
    );

    // Place mines
    let minesPlaced = 0;
    while (minesPlaced < MINES_COUNT) {
      const x = Math.floor(Math.random() * BOARD_SIZE);
      const y = Math.floor(Math.random() * BOARD_SIZE);
      if (!newBoard[y][x].isMine) {
        newBoard[y][x].isMine = true;
        minesPlaced++;
      }
    }

    // Calculate neighbors
    for (let y = 0; y < BOARD_SIZE; y++) {
      for (let x = 0; x < BOARD_SIZE; x++) {
        if (!newBoard[y][x].isMine) {
          let count = 0;
          for (let dy = -1; dy <= 1; dy++) {
            for (let dx = -1; dx <= 1; dx++) {
              if (y + dy >= 0 && y + dy < BOARD_SIZE && x + dx >= 0 && x + dx < BOARD_SIZE) {
                if (newBoard[y + dy][x + dx].isMine) count++;
              }
            }
          }
          newBoard[y][x].neighborMines = count;
        }
      }
    }

    setBoard(newBoard);
    setGameOver(false);
    setWin(false);
    setFlags(MINES_COUNT);
    setTime(0);
    setStarted(false);
  };

  const revealCell = (x: number, y: number) => {
    if (gameOver || win || board[y][x].isFlagged || board[y][x].isRevealed) return;

    if (!started) setStarted(true);

    const newBoard = [...board];
    const cell = newBoard[y][x];

    if (cell.isMine) {
      cell.isRevealed = true;
      setBoard(newBoard);
      setGameOver(true);
      return;
    }

    const floodFill = (cx: number, cy: number) => {
      if (cx < 0 || cx >= BOARD_SIZE || cy < 0 || cy >= BOARD_SIZE || newBoard[cy][cx].isRevealed || newBoard[cy][cx].isFlagged) return;

      newBoard[cy][cx].isRevealed = true;

      if (newBoard[cy][cx].neighborMines === 0) {
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
             floodFill(cx + dx, cy + dy);
          }
        }
      }
    };

    floodFill(x, y);
    setBoard(newBoard);

    // Check win
    const unrevealedSafeCells = newBoard.flat().filter(c => !c.isMine && !c.isRevealed).length;
    if (unrevealedSafeCells === 0) {
      setWin(true);
    }
  };

  const toggleFlag = (e: React.MouseEvent, x: number, y: number) => {
    e.preventDefault();
    if (gameOver || win || board[y][x].isRevealed) return;

    const newBoard = [...board];
    if (newBoard[y][x].isFlagged) {
      newBoard[y][x].isFlagged = false;
      setFlags(f => f + 1);
    } else {
      if (flags > 0) {
        newBoard[y][x].isFlagged = true;
        setFlags(f => f - 1);
      }
    }
    setBoard(newBoard);
  };

  return (
    <div className="h-full flex flex-col items-center justify-center bg-[#c0c0c0] p-4 select-none font-mono border-4 border-white border-r-gray-500 border-b-gray-500">
      <div className="w-full flex justify-between items-center mb-4 bg-[#c0c0c0] border-2 border-gray-500 border-r-white border-b-white p-2">
        <div className="bg-black text-red-600 px-2 text-2xl font-bold">{String(flags).padStart(3, '0')}</div>
        <button onClick={initGame} className="text-2xl p-1 active:translate-y-[1px] border-2 border-white border-r-gray-500 border-b-gray-500 active:border-gray-500 active:border-r-white active:border-b-white bg-[#c0c0c0]">
          {gameOver ? '😵' : win ? '😎' : '🙂'}
        </button>
        <div className="bg-black text-red-600 px-2 text-2xl font-bold">{String(time).padStart(3, '0')}</div>
      </div>

      <div 
        className="grid gap-[2px] bg-gray-500 p-[2px] border-4 border-gray-500 border-r-white border-b-white"
        style={{ gridTemplateColumns: `repeat(${BOARD_SIZE}, 1fr)` }}
      >
        {board.map((row, y) => row.map((cell, x) => (
          <div
            key={`${x}-${y}`}
            className={`w-8 h-8 flex items-center justify-center text-sm font-bold cursor-pointer
              ${cell.isRevealed 
                ? 'bg-[#c0c0c0] border border-gray-400' 
                : 'bg-[#c0c0c0] border-2 border-white border-r-gray-500 border-b-gray-500 hover:brightness-105 active:border-gray-500 active:border-r-white active:border-b-white'
              }
              ${cell.isRevealed && cell.isMine ? 'bg-red-500' : ''}
            `}
            onClick={() => revealCell(x, y)}
            onContextMenu={(e) => toggleFlag(e, x, y)}
          >
            {cell.isRevealed ? (
              cell.isMine ? <Bomb size={16} /> : cell.neighborMines > 0 ? (
                <span style={{ color: ['blue', 'green', 'red', 'darkblue', 'brown', 'cyan', 'black', 'gray'][cell.neighborMines - 1] }}>
                  {cell.neighborMines}
                </span>
              ) : ''
            ) : (
              cell.isFlagged ? <Flag size={14} className="text-red-600 fill-red-600" /> : ''
            )}
          </div>
        )))}
      </div>
    </div>
  );
};

export default Minesweeper;

import React, { useState, useEffect, useRef } from 'react';
import { RotateCw, Play } from 'lucide-react';

const GRID_SIZE = 20;
const INITIAL_SPEED = 150;

type Point = { x: number; y: number };
type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT';

interface SnakeProps {
  onInteraction: (type: string, data?: any) => void;
}

const Snake: React.FC<SnakeProps> = ({ onInteraction }) => {
  const [snake, setSnake] = useState<Point[]>([{ x: 10, y: 10 }]);
  const [food, setFood] = useState<Point>({ x: 15, y: 10 });
  const [direction, setDirection] = useState<Direction>('RIGHT');
  const [gameOver, setGameOver] = useState(false);
  const [score, setScore] = useState(0);
  const [highScore, setHighScore] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);

  // Refs for state that updates frequently to avoid closure staleness in intervals
  const directionRef = useRef<Direction>('RIGHT');
  const snakeRef = useRef<Point[]>([{ x: 10, y: 10 }]);
  const isPlayingRef = useRef(false);

  useEffect(() => {
    // Sync refs with state
    directionRef.current = direction;
    snakeRef.current = snake;
    isPlayingRef.current = isPlaying;
  }, [direction, snake, isPlaying]);

  const generateFood = (currentSnake: Point[]): Point => {
    while (true) {
      const x = Math.floor(Math.random() * GRID_SIZE);
      const y = Math.floor(Math.random() * GRID_SIZE);
      const isOnSnake = currentSnake.some(segment => segment.x === x && segment.y === y);
      if (!isOnSnake) return { x, y };
    }
  };

  const resetGame = () => {
    if (gameOver || isPlaying) {
      onInteraction('game_restart', 'snake');
    }

    const initialSnake = [{ x: 10, y: 10 }];
    setSnake(initialSnake);
    snakeRef.current = initialSnake;

    setFood(generateFood(initialSnake));
    setDirection('RIGHT');
    directionRef.current = 'RIGHT';

    setScore(0);
    setGameOver(false);
    setIsPlaying(true);
  };

  const handleKeyDown = (e: KeyboardEvent) => {
    if (!isPlayingRef.current) return;

    switch (e.key) {
      case 'ArrowUp':
        if (directionRef.current !== 'DOWN') setDirection('UP');
        e.preventDefault();
        break;
      case 'ArrowDown':
        if (directionRef.current !== 'UP') setDirection('DOWN');
        e.preventDefault();
        break;
      case 'ArrowLeft':
        if (directionRef.current !== 'RIGHT') setDirection('LEFT');
        e.preventDefault();
        break;
      case 'ArrowRight':
        if (directionRef.current !== 'LEFT') setDirection('RIGHT');
        e.preventDefault();
        break;
    }
  };

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  useEffect(() => {
    if (!isPlaying) return;

    const gameLoop = setInterval(() => {
      const currentHead = snakeRef.current[0];
      const currentDir = directionRef.current;

      const newHead = { ...currentHead };

      switch (currentDir) {
        case 'UP': newHead.y -= 1; break;
        case 'DOWN': newHead.y += 1; break;
        case 'LEFT': newHead.x -= 1; break;
        case 'RIGHT': newHead.x += 1; break;
      }

      // Check Walls
      if (
        newHead.x < 0 || 
        newHead.x >= GRID_SIZE || 
        newHead.y < 0 || 
        newHead.y >= GRID_SIZE
      ) {
        setGameOver(true);
        setIsPlaying(false);
        return;
      }

      // Check Self Collision
      if (snakeRef.current.some(segment => segment.x === newHead.x && segment.y === newHead.y)) {
         setGameOver(true);
         setIsPlaying(false);
         return;
      }

      const newSnake = [newHead, ...snakeRef.current];

      // Check Food
      if (newHead.x === food.x && newHead.y === food.y) {
        setScore(s => {
          const newScore = s + 10;
          if (newScore > highScore) setHighScore(newScore);
          return newScore;
        });
        setFood(generateFood(newSnake));
      } else {
        newSnake.pop(); // Remove tail
      }

      setSnake(newSnake);

    }, INITIAL_SPEED);

    return () => clearInterval(gameLoop);
  }, [isPlaying, food, highScore]);

  return (
    <div className="h-full flex flex-col items-center justify-center bg-[#c0c0c0] p-4 select-none font-mono border-4 border-white border-r-gray-500 border-b-gray-500">

      {/* Header Bar */}
      <div className="w-full max-w-[400px] flex justify-between items-center mb-4 bg-[#c0c0c0] border-2 border-gray-500 border-r-white border-b-white p-2">
        <div className="flex flex-col">
          <span className="text-[10px] uppercase text-gray-600 font-bold leading-none mb-1">Score</span>
          <div className="bg-black text-red-600 px-2 text-2xl font-bold font-mono tracking-widest">{String(score).padStart(3, '0')}</div>
        </div>

        <button 
          onClick={resetGame} 
          className="w-12 h-12 flex items-center justify-center active:translate-y-[1px] border-2 border-white border-r-gray-500 border-b-gray-500 active:border-gray-500 active:border-r-white active:border-b-white bg-[#c0c0c0]"
        >
          {gameOver ? <RotateCw size={24} /> : isPlaying ? <div className="w-3 h-3 bg-green-600 rounded-full animate-pulse" /> : <Play size={24} />}
        </button>

        <div className="flex flex-col items-end">
          <span className="text-[10px] uppercase text-gray-600 font-bold leading-none mb-1">High Score</span>
          <div className="bg-black text-red-600 px-2 text-2xl font-bold font-mono tracking-widest">{String(highScore).padStart(3, '0')}</div>
        </div>
      </div>

      {/* Game Board */}
      <div 
        className="grid gap-[1px] bg-gray-700 p-[4px] border-4 border-gray-500 border-r-white border-b-white relative"
        style={{ 
          gridTemplateColumns: `repeat(${GRID_SIZE}, 1fr)`,
          width: 'min(80vh, 100%)',
          maxWidth: '400px',
          aspectRatio: '1/1'
        }}
      >
        {gameOver && (
          <div className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-black/50 backdrop-blur-[2px]">
             <span className="text-white font-bold text-2xl mb-2 drop-shadow-md">GAME OVER</span>
             <button 
               onClick={resetGame}
               className="px-4 py-2 bg-[#c0c0c0] border-2 border-white border-r-gray-500 border-b-gray-500 font-bold hover:bg-white transition-colors text-sm"
             >
               TRY AGAIN
             </button>
          </div>
        )}

        {Array.from({ length: GRID_SIZE * GRID_SIZE }).map((_, i) => {
          const x = i % GRID_SIZE;
          const y = Math.floor(i / GRID_SIZE);
          const isSnake = snake.some(s => s.x === x && s.y === y);
          const isHead = snake[0].x === x && snake[0].y === y;
          const isFood = food.x === x && food.y === y;

          return (
            <div
              key={i}
              className={`w-full h-full 
                ${isHead ? 'bg-green-400 z-10' : 
                  isSnake ? 'bg-green-600' : 
                  isFood ? 'bg-red-500 rounded-full scale-75' : 'bg-[#e0e0e0]'}
              `}
              style={isSnake ? { boxShadow: 'inset 0 0 0 1px rgba(0,0,0,0.1)' } : {}}
            />
          );
        })}
      </div>

      <div className="mt-4 text-gray-600 text-xs text-center font-bold">
        USE ARROW KEYS TO MOVE
      </div>
    </div>
  );
};

export default Snake;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { INITIAL_FILES, WALLPAPERS, ACHIEVEMENTS_LIST } from './constants';
import { FileSystemItem, WindowState, AppID, FileType } from './types';
import Desktop from './components/os/Desktop';
import TopBar from './components/os/TopBar';
import Dock from './components/os/Dock';
import Window from './components/os/Window';
import Screensaver from './components/os/Screensaver';
import Finder from './components/apps/Finder';
import Terminal from './components/apps/Terminal';
import TextEditor from './components/apps/TextEditor';
import Minesweeper from './components/apps/Minesweeper';
import Snake from './components/apps/Snake';
import EmailClient from './components/apps/Email';
import PDFViewer from './components/apps/PDFViewer';
import SystemPreferences from './components/apps/SystemPreferences';
import Achievements from './components/apps/Achievements';
import Notification from './components/os/Notification';
import { AnimatePresence, motion } from 'framer-motion';
import { AlertTriangle } from 'lucide-react';

// App Mapping
const APP_COMPONENTS: Record<string, any> = {
  [AppID.FINDER]: Finder,
  [AppID.TERMINAL]: Terminal,
  [AppID.TEXT_EDITOR]: TextEditor,
  [AppID.MINESWEEPER]: Minesweeper,
  [AppID.SNAKE]: Snake,
  [AppID.EMAIL]: EmailClient,
  [AppID.PDF_VIEWER]: PDFViewer,
  [AppID.SYSTEM_PREFERENCES]: SystemPreferences,
  [AppID.ACHIEVEMENTS]: Achievements,
  [AppID.IMAGE_VIEWER]: ({ file }: { file: FileSystemItem }) => (
    <div className="h-full flex items-center justify-center bg-black">
      <img src={file.src} alt={file.name} className="max-w-full max-h-full object-contain" />
    </div>
  ),
  [AppID.TRASH]: Finder // Use Finder for Trash to show files
};

const DEFAULT_WINDOW_SIZE = { width: 800, height: 600 };

export default function App() {
  const [files, setFiles] = useState(INITIAL_FILES);
  const [windows, setWindows] = useState<WindowState[]>([]);
  const [activeWindowId, setActiveWindowId] = useState<string | null>(null);
  const [selectedDesktopIds, setSelectedDesktopIds] = useState<string[]>([]);
  const [zIndexCounter, setZIndexCounter] = useState(10);

  // Settings State
  const [currentWallpaper, setCurrentWallpaper] = useState(WALLPAPERS[0].value);
  const [screensaverEnabled, setScreensaverEnabled] = useState(true);
  const [screensaverTimeout, setScreensaverTimeout] = useState(60000); // 1 minute
  const [isScreensaverActive, setIsScreensaverActive] = useState(false);
  const [lastActivity, setLastActivity] = useState(Date.now());

  // Alert State
  const [alertConfig, setAlertConfig] = useState<{ message: string; isOpen: boolean }>({ message: '', isOpen: false });

  // Achievements State
  const [achievements, setAchievements] = useState<Record<string, boolean>>({});
  const [notification, setNotification] = useState<{ id: string; title: string; message: string } | null>(null);

  // Tracking Stats
  const [stats, setStats] = useState({
    openedFiles: new Set<string>(),
    openedApps: new Set<string>(),
    trashFilesOpened: new Set<string>(),
    gameRestarts: new Map<string, number>(),
  });

  // -- Achievements Logic --

  const unlockAchievement = useCallback((id: string) => {
    setAchievements(prev => {
      if (prev[id]) return prev; // Already unlocked

      // Find achievement details
      const details = ACHIEVEMENTS_LIST.find(a => a.id === id);
      if (details) {
        setNotification({
          id,
          title: 'Achievement Unlocked',
          message: details.name
        });
      }

      return { ...prev, [id]: true };
    });
  }, []);

  // First Boot Achievement
  useEffect(() => {
    unlockAchievement('first_boot');
  }, [unlockAchievement]);

  // -- Screensaver Logic --
  const resetIdleTimer = useCallback(() => {
    setLastActivity(Date.now());
    if (isScreensaverActive) {
      setIsScreensaverActive(false);
    }
  }, [isScreensaverActive]);

  useEffect(() => {
    if (!screensaverEnabled) return;

    const checkIdle = () => {
      if (Date.now() - lastActivity > screensaverTimeout) {
        setIsScreensaverActive(true);
      }
    };

    const interval = setInterval(checkIdle, 1000);

    // Add event listeners for activity
    window.addEventListener('mousemove', resetIdleTimer);
    window.addEventListener('keydown', resetIdleTimer);
    window.addEventListener('click', resetIdleTimer);

    return () => {
      clearInterval(interval);
      window.removeEventListener('mousemove', resetIdleTimer);
      window.removeEventListener('keydown', resetIdleTimer);
      window.removeEventListener('click', resetIdleTimer);
    };
  }, [screensaverEnabled, screensaverTimeout, lastActivity, resetIdleTimer]);


  // -- Window Management --

  const openWindow = (appId: AppID, contentId?: string) => {
    // Achievements tracking: Apps
    setStats(prev => {
      const next = { ...prev };
      next.openedApps.add(appId);

      // Check Gamer
      if (next.openedApps.has(AppID.MINESWEEPER) && next.openedApps.has(AppID.SNAKE)) {
        unlockAchievement('gamer');
      }
      return next;
    });

    // Reference Check
    if (appId === AppID.EMAIL) {
      unlockAchievement('reference_check');
    }

    // Check if already open
    const existing = windows.find(w => w.appId === appId && w.contentId === contentId);
    if (existing) {
      focusWindow(existing.id);
      return;
    }

    const newWindow: WindowState = {
      id: Math.random().toString(36).substr(2, 9),
      appId,
      contentId,
      title: contentId ? files[contentId].name : getAppName(appId),
      isMinimized: false,
      isMaximized: false,
      zIndex: zIndexCounter + 1,
      position: { x: 50 + (windows.length * 20), y: 50 + (windows.length * 20) },
      size: DEFAULT_WINDOW_SIZE,
    };

    setZIndexCounter(prev => prev + 1);
    setWindows([...windows, newWindow]);
    setActiveWindowId(newWindow.id);
  };

  const closeWindow = (id: string) => {
    setWindows(windows.filter(w => w.id !== id));
    if (activeWindowId === id) {
      setActiveWindowId(null);
    }
  };

  const focusWindow = (id: string) => {
    setActiveWindowId(id);
    setZIndexCounter(prev => prev + 1);
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: false, zIndex: zIndexCounter + 1 } : w));
  };

  const toggleMinimize = (id: string) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: !w.isMinimized } : w));
    if (activeWindowId === id) setActiveWindowId(null);
  };

  const toggleMaximize = (id: string) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMaximized: !w.isMaximized } : w));
    focusWindow(id);
  };

  const resizeWindow = (id: string, width: number, height: number) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, size: { width, height } } : w));
  };

  // -- File System Interaction --

  const openFile = (item: FileSystemItem) => {
    // Achievements tracking: Files
    setStats(prev => {
      const next = { ...prev };
      next.openedFiles.add(item.id);

      // Desktop Explorer
      if (next.openedFiles.size >= 5) {
        unlockAchievement('desktop_explorer');
      }

      // Context Matters
      if (next.openedFiles.has('bio_txt') && next.openedFiles.has('values_md')) {
        unlockAchievement('context_matters');
      }

      // Trash Explorer
      if (item.parentId === 'trash_bin') {
        next.trashFilesOpened.add(item.id);
        const trashChildren = files['trash_bin'].children || [];
        if (trashChildren.length > 0 && next.trashFilesOpened.size >= trashChildren.length) {
          unlockAchievement('trash_explorer');
        }
      }

      return next;
    });

    // Actually Read It
    if (item.id === 'file_cv') {
      unlockAchievement('actually_read_it');
    }

    // Check for locks
    if (item.lockedMessage) {
      setAlertConfig({ message: item.lockedMessage, isOpen: true });
      return;
    }

    // Special handling for Trash app to ensure it opens the Trash window
    if (item.appId === AppID.TRASH) {
       openWindow(AppID.TRASH, item.id);
       return;
    }

    if (item.type === FileType.FOLDER) {
      const finderOpen = windows.find(w => w.appId === AppID.FINDER);
      if (finderOpen) {
        focusWindow(finderOpen.id);
      } else {
        openWindow(AppID.FINDER, item.id);
      }
      return;
    }

    if (item.appId) {
      openWindow(item.appId, item.id);
    } else {
      openWindow(AppID.TEXT_EDITOR, item.id);
    }
  };

  const handleDesktopSelect = (id: string, multi: boolean) => {
    if (!id) {
      setSelectedDesktopIds([]);
      return;
    }
    if (multi) {
      setSelectedDesktopIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    } else {
      setSelectedDesktopIds([id]);
    }
  };

  const handleAppInteraction = (type: string, data?: any) => {
    if (type === 'terminal_command') {
      unlockAchievement('command_line_curious');
    }
    if (type === 'terminal_help') {
      unlockAchievement('help_actually');
    }
    if (type === 'minesweeper_loss') {
      unlockAchievement('first_mine');
    }
    if (type === 'minesweeper_win') {
      unlockAchievement('clean_board');
    }
    if (type === 'game_restart') {
      const gameId = data; // 'snake' or 'minesweeper'
      setStats(prev => {
        const next = { ...prev };
        const count = (next.gameRestarts.get(gameId) || 0) + 1;
        next.gameRestarts.set(gameId, count);

        if (count >= 1) { // Played more than once (initial play + 1 restart)
          unlockAchievement('just_one_more');
        }
        return next;
      });
    }
  };

  const getAppName = (id: AppID) => {
    switch (id) {
      case AppID.FINDER: return 'Finder';
      case AppID.TERMINAL: return 'Terminal';
      case AppID.EMAIL: return 'Mail';
      case AppID.MINESWEEPER: return 'Minesweeper';
      case AppID.SNAKE: return 'Snake';
      case AppID.TEXT_EDITOR: return 'Text Editor';
      case AppID.IMAGE_VIEWER: return 'Preview';
      case AppID.PDF_VIEWER: return 'PDF Viewer';
      case AppID.SYSTEM_PREFERENCES: return 'Settings';
      case AppID.ACHIEVEMENTS: return 'Achievements';
      case AppID.TRASH: return 'Trash';
      default: return 'App';
    }
  };

  const getActiveAppTitle = () => {
    if (!activeWindowId) return 'Finder';
    const win = windows.find(w => w.id === activeWindowId);
    return win ? getAppName(win.appId) : 'Finder';
  };

  return (
    <div 
      className="h-screen w-screen overflow-hidden bg-cover bg-center text-sm font-sans flex flex-col relative select-none transition-all duration-700 ease-in-out"
      style={{ backgroundImage: currentWallpaper }}
    >
      <TopBar 
        activeAppTitle={getActiveAppTitle()} 
        onOpenApp={openWindow}
        onOpenAchievements={() => openWindow(AppID.ACHIEVEMENTS)}
        hasUnreadAchievements={false} // Simple implementation: glow resets on click essentially
      />

      <div className="flex-1 relative overflow-hidden">
        <Desktop 
          files={files} 
          selectedIds={selectedDesktopIds} 
          onSelect={handleDesktopSelect} 
          onOpen={openFile}
        />

        <AnimatePresence>
          {windows.map(win => {
            const AppComponent = APP_COMPONENTS[win.appId];
            const file = win.contentId ? files[win.contentId] : null;

            // Determine initial path for Finder-based apps
            let initialPath = 'desktop';
            if (win.appId === AppID.TRASH) {
              initialPath = 'trash_bin';
            } else if (win.appId === AppID.FINDER) {
              initialPath = win.contentId || 'desktop';
            }

            return (
              <Window
                key={win.id}
                window={win}
                isActive={activeWindowId === win.id}
                onClose={closeWindow}
                onFocus={focusWindow}
                onMinimize={toggleMinimize}
                onMaximize={toggleMaximize}
                onResize={resizeWindow}
              >
                <AppComponent 
                  file={file} 
                  files={files} 
                  initialPath={initialPath}
                  onNavigate={(id: string) => {}}
                  onOpenFile={openFile}
                  onOpenApp={openWindow}
                  onInteraction={handleAppInteraction}

                  // Settings Props
                  currentWallpaper={currentWallpaper}
                  onWallpaperChange={setCurrentWallpaper}
                  screensaverEnabled={screensaverEnabled}
                  onScreensaverToggle={setScreensaverEnabled}
                  screensaverTimeout={screensaverTimeout}
                  onScreensaverTimeoutChange={setScreensaverTimeout}

                  // Achievements Props
                  unlocked={achievements}
                />
              </Window>
            );
          })}
        </AnimatePresence>
      </div>

      <Dock 
        openApps={windows.map(w => w.appId)} 
        onOpenApp={(appId) => openWindow(appId)}
      />

      <Notification 
        notification={notification} 
        onClose={() => setNotification(null)}
        onClick={() => {
          setNotification(null);
          openWindow(AppID.ACHIEVEMENTS);
        }}
      />

      {/* System Alert Modal */}
      <AnimatePresence>
        {alertConfig.isOpen && (
          <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/20 backdrop-blur-[2px]">
            <motion.div 
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              transition={{ type: "spring", stiffness: 400, damping: 25 }}
              className="bg-white/90 dark:bg-stone-800/90 backdrop-blur-xl border border-white/20 dark:border-white/10 shadow-2xl rounded-xl p-6 w-80 max-w-full text-center flex flex-col items-center gap-4"
            >
              <div className="w-12 h-12 bg-stone-100 dark:bg-stone-700 rounded-full flex items-center justify-center">
                 <AlertTriangle className="text-stone-500 dark:text-stone-300" size={24} />
              </div>
              <div className="flex-1">
                <h3 className="font-bold text-lg text-stone-900 dark:text-stone-100 mb-1">Access Denied</h3>
                <p className="text-stone-600 dark:text-stone-300 leading-relaxed">{alertConfig.message}</p>
              </div>
              <button 
                onClick={() => setAlertConfig(prev => ({ ...prev, isOpen: false }))}
                className="w-full py-2 bg-stone-800 hover:bg-stone-900 dark:bg-stone-200 dark:hover:bg-white text-white dark:text-stone-900 font-medium rounded-lg transition-colors"
              >
                OK
              </button>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {isScreensaverActive && (
          <Screensaver onWake={resetIdleTimer} />
        )}
      </AnimatePresence>
    </div>
  );
}

import React from 'react';
import { ACHIEVEMENTS_LIST } from '../../constants';
import { Check, Lock } from 'lucide-react';

interface AchievementsProps {
  unlocked: Record<string, boolean>;
}

const Achievements: React.FC<AchievementsProps> = ({ unlocked }) => {
  return (
    <div className="h-full bg-[#f5f5f7] dark:bg-[#1e1e1e] p-6 overflow-auto">
      <div className="max-w-2xl mx-auto">
        <h2 className="text-2xl font-bold mb-6 text-stone-800 dark:text-stone-100 flex items-center gap-3">
          Achievements
          <span className="text-sm font-normal text-stone-500 bg-stone-200 dark:bg-stone-800 px-2 py-1 rounded-full">
            {Object.values(unlocked).filter(Boolean).length} / {ACHIEVEMENTS_LIST.length}
          </span>
        </h2>

        <div className="grid gap-3">
          {ACHIEVEMENTS_LIST.map((achievement) => {
            const isUnlocked = unlocked[achievement.id];

            return (
              <div 
                key={achievement.id}
                className={`
                  relative flex items-center justify-between p-4 rounded-xl border transition-all duration-300
                  ${isUnlocked 
                    ? 'bg-white dark:bg-stone-800 border-stone-200 dark:border-stone-700 shadow-sm' 
                    : 'bg-stone-100 dark:bg-stone-900/50 border-transparent opacity-60'
                  }
                `}
              >
                <div className="flex items-center gap-4">
                  <div className={`
                    w-10 h-10 rounded-full flex items-center justify-center transition-colors flex-shrink-0
                    ${isUnlocked 
                      ? 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-600 dark:text-yellow-500' 
                      : 'bg-stone-200 dark:bg-stone-800 text-stone-400'
                    }
                  `}>
                    {isUnlocked ? <Check size={20} strokeWidth={3} /> : <Lock size={18} />}
                  </div>
                  <div className="flex flex-col">
                    <span className={`font-semibold ${isUnlocked ? 'text-stone-900 dark:text-stone-100' : 'text-stone-500'}`}>
                      {achievement.name}
                    </span>
                    <span className={`text-sm ${isUnlocked ? 'text-stone-600 dark:text-stone-400' : 'text-stone-400 dark:text-stone-600'}`}>
                      {isUnlocked ? achievement.description : '???'}
                    </span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default Achievements;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { INITIAL_FILES, WALLPAPERS, ACHIEVEMENTS_LIST } from './constants';
import { FileSystemItem, WindowState, AppID, FileType } from './types';
import Desktop from './components/os/Desktop';
import TopBar from './components/os/TopBar';
import Dock from './components/os/Dock';
import Window from './components/os/Window';
import Screensaver from './components/os/Screensaver';
import Finder from './components/apps/Finder';
import Terminal from './components/apps/Terminal';
import TextEditor from './components/apps/TextEditor';
import Minesweeper from './components/apps/Minesweeper';
import Snake from './components/apps/Snake';
import EmailClient from './components/apps/Email';
import PDFViewer from './components/apps/PDFViewer';
import SystemPreferences from './components/apps/SystemPreferences';
import Achievements from './components/apps/Achievements';
import Notification from './components/os/Notification';
import { AnimatePresence, motion } from 'framer-motion';
import { AlertTriangle } from 'lucide-react';

// App Mapping
const APP_COMPONENTS: Record<string, any> = {
  [AppID.FINDER]: Finder,
  [AppID.TERMINAL]: Terminal,
  [AppID.TEXT_EDITOR]: TextEditor,
  [AppID.MINESWEEPER]: Minesweeper,
  [AppID.SNAKE]: Snake,
  [AppID.EMAIL]: EmailClient,
  [AppID.PDF_VIEWER]: PDFViewer,
  [AppID.SYSTEM_PREFERENCES]: SystemPreferences,
  [AppID.ACHIEVEMENTS]: Achievements,
  [AppID.IMAGE_VIEWER]: ({ file }: { file: FileSystemItem }) => (
    <div className="h-full flex items-center justify-center bg-black">
      <img src={file.src} alt={file.name} className="max-w-full max-h-full object-contain" />
    </div>
  ),
  [AppID.TRASH]: Finder // Use Finder for Trash to show files
};

const DEFAULT_WINDOW_SIZE = { width: 800, height: 600 };

export default function App() {
  const [files, setFiles] = useState(INITIAL_FILES);
  const [windows, setWindows] = useState<WindowState[]>([]);
  const [activeWindowId, setActiveWindowId] = useState<string | null>(null);
  const [selectedDesktopIds, setSelectedDesktopIds] = useState<string[]>([]);
  const [zIndexCounter, setZIndexCounter] = useState(10);

  // Settings State
  const [currentWallpaper, setCurrentWallpaper] = useState(WALLPAPERS[0].value);
  const [screensaverEnabled, setScreensaverEnabled] = useState(true);
  const [screensaverTimeout, setScreensaverTimeout] = useState(60000); // 1 minute
  const [isScreensaverActive, setIsScreensaverActive] = useState(false);
  const [lastActivity, setLastActivity] = useState(Date.now());

  // Alert State
  const [alertConfig, setAlertConfig] = useState<{ message: string; isOpen: boolean }>({ message: '', isOpen: false });

  // Achievements State - Persisted
  const [achievements, setAchievements] = useState<Record<string, boolean>>(() => {
    try {
      const saved = localStorage.getItem('portfolio_os_achievements');
      return saved ? JSON.parse(saved) : {};
    } catch (e) {
      return {};
    }
  });
  const [notification, setNotification] = useState<{ id: string; title: string; message: string } | null>(null);

  // Persist Achievements
  useEffect(() => {
    localStorage.setItem('portfolio_os_achievements', JSON.stringify(achievements));
  }, [achievements]);

  // Tracking Stats
  const [stats, setStats] = useState({
    openedFiles: new Set<string>(),
    openedApps: new Set<string>(),
    trashFilesOpened: new Set<string>(),
    gameRestarts: new Map<string, number>(),
  });

  // -- System Reset --
  const handleSystemReset = () => {
    if (window.confirm('Are you sure you want to restart? This will reset your session and clear all achievements.')) {
      localStorage.removeItem('portfolio_os_achievements');
      window.location.reload();
    }
  };

  // -- Achievements Logic --

  const unlockAchievement = useCallback((id: string) => {
    setAchievements(prev => {
      if (prev[id]) return prev; // Already unlocked

      // Find achievement details
      const details = ACHIEVEMENTS_LIST.find(a => a.id === id);
      if (details) {
        setNotification({
          id,
          title: 'Achievement Unlocked',
          message: details.name
        });
      }

      return { ...prev, [id]: true };
    });
  }, []);

  // First Boot Achievement
  useEffect(() => {
    unlockAchievement('first_boot');
  }, [unlockAchievement]);

  // -- Screensaver Logic --
  const resetIdleTimer = useCallback(() => {
    setLastActivity(Date.now());
    if (isScreensaverActive) {
      setIsScreensaverActive(false);
    }
  }, [isScreensaverActive]);

  useEffect(() => {
    if (!screensaverEnabled) return;

    const checkIdle = () => {
      if (Date.now() - lastActivity > screensaverTimeout) {
        setIsScreensaverActive(true);
      }
    };

    const interval = setInterval(checkIdle, 1000);

    // Add event listeners for activity
    window.addEventListener('mousemove', resetIdleTimer);
    window.addEventListener('keydown', resetIdleTimer);
    window.addEventListener('click', resetIdleTimer);

    return () => {
      clearInterval(interval);
      window.removeEventListener('mousemove', resetIdleTimer);
      window.removeEventListener('keydown', resetIdleTimer);
      window.removeEventListener('click', resetIdleTimer);
    };
  }, [screensaverEnabled, screensaverTimeout, lastActivity, resetIdleTimer]);


  // -- Window Management --

  const openWindow = (appId: AppID, contentId?: string) => {
    // Achievements tracking: Apps
    setStats(prev => {
      const next = { ...prev };
      next.openedApps.add(appId);

      // Check Gamer
      if (next.openedApps.has(AppID.MINESWEEPER) && next.openedApps.has(AppID.SNAKE)) {
        unlockAchievement('gamer');
      }
      return next;
    });

    // Reference Check
    if (appId === AppID.EMAIL) {
      unlockAchievement('reference_check');
    }

    // Check if already open
    const existing = windows.find(w => w.appId === appId && w.contentId === contentId);
    if (existing) {
      focusWindow(existing.id);
      return;
    }

    const newWindow: WindowState = {
      id: Math.random().toString(36).substr(2, 9),
      appId,
      contentId,
      title: contentId ? files[contentId].name : getAppName(appId),
      isMinimized: false,
      isMaximized: false,
      zIndex: zIndexCounter + 1,
      position: { x: 50 + (windows.length * 20), y: 50 + (windows.length * 20) },
      size: DEFAULT_WINDOW_SIZE,
    };

    setZIndexCounter(prev => prev + 1);
    setWindows([...windows, newWindow]);
    setActiveWindowId(newWindow.id);
  };

  const closeWindow = (id: string) => {
    setWindows(windows.filter(w => w.id !== id));
    if (activeWindowId === id) {
      setActiveWindowId(null);
    }
  };

  const focusWindow = (id: string) => {
    setActiveWindowId(id);
    setZIndexCounter(prev => prev + 1);
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: false, zIndex: zIndexCounter + 1 } : w));
  };

  const toggleMinimize = (id: string) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: !w.isMinimized } : w));
    if (activeWindowId === id) setActiveWindowId(null);
  };

  const toggleMaximize = (id: string) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMaximized: !w.isMaximized } : w));
    focusWindow(id);
  };

  const resizeWindow = (id: string, width: number, height: number) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, size: { width, height } } : w));
  };

  // -- File System Interaction --

  const openFile = (item: FileSystemItem) => {
    // Achievements tracking: Files
    setStats(prev => {
      const next = { ...prev };
      next.openedFiles.add(item.id);

      // Desktop Explorer
      if (next.openedFiles.size >= 5) {
        unlockAchievement('desktop_explorer');
      }

      // Context Matters
      if (next.openedFiles.has('bio_txt') && next.openedFiles.has('values_md')) {
        unlockAchievement('context_matters');
      }

      // Trash Explorer
      if (item.parentId === 'trash_bin') {
        next.trashFilesOpened.add(item.id);
        const trashChildren = files['trash_bin'].children || [];
        if (trashChildren.length > 0 && next.trashFilesOpened.size >= trashChildren.length) {
          unlockAchievement('trash_explorer');
        }
      }

      return next;
    });

    // Actually Read It
    if (item.id === 'file_cv') {
      unlockAchievement('actually_read_it');
    }

    // Check for locks
    if (item.lockedMessage) {
      setAlertConfig({ message: item.lockedMessage, isOpen: true });
      return;
    }

    // Special handling for Trash app to ensure it opens the Trash window
    if (item.appId === AppID.TRASH) {
       openWindow(AppID.TRASH, item.id);
       return;
    }

    if (item.type === FileType.FOLDER) {
      const finderOpen = windows.find(w => w.appId === AppID.FINDER);
      if (finderOpen) {
        focusWindow(finderOpen.id);
      } else {
        openWindow(AppID.FINDER, item.id);
      }
      return;
    }

    if (item.appId) {
      openWindow(item.appId, item.id);
    } else {
      openWindow(AppID.TEXT_EDITOR, item.id);
    }
  };

  const handleDesktopSelect = (id: string, multi: boolean) => {
    if (!id) {
      setSelectedDesktopIds([]);
      return;
    }
    if (multi) {
      setSelectedDesktopIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    } else {
      setSelectedDesktopIds([id]);
    }
  };

  const handleAppInteraction = (type: string, data?: any) => {
    if (type === 'terminal_command') {
      unlockAchievement('command_line_curious');
    }
    if (type === 'terminal_help') {
      unlockAchievement('help_actually');
    }
    if (type === 'minesweeper_loss') {
      unlockAchievement('first_mine');
    }
    if (type === 'minesweeper_win') {
      unlockAchievement('clean_board');
    }
    if (type === 'game_restart') {
      const gameId = data; // 'snake' or 'minesweeper'
      setStats(prev => {
        const next = { ...prev };
        const count = (next.gameRestarts.get(gameId) || 0) + 1;
        next.gameRestarts.set(gameId, count);

        if (count >= 1) { // Played more than once (initial play + 1 restart)
          unlockAchievement('just_one_more');
        }
        return next;
      });
    }
  };

  const getAppName = (id: AppID) => {
    switch (id) {
      case AppID.FINDER: return 'Finder';
      case AppID.TERMINAL: return 'Terminal';
      case AppID.EMAIL: return 'Mail';
      case AppID.MINESWEEPER: return 'Minesweeper';
      case AppID.SNAKE: return 'Snake';
      case AppID.TEXT_EDITOR: return 'Text Editor';
      case AppID.IMAGE_VIEWER: return 'Preview';
      case AppID.PDF_VIEWER: return 'PDF Viewer';
      case AppID.SYSTEM_PREFERENCES: return 'Settings';
      case AppID.ACHIEVEMENTS: return 'Achievements';
      case AppID.TRASH: return 'Trash';
      default: return 'App';
    }
  };

  const getActiveAppTitle = () => {
    if (!activeWindowId) return 'Finder';
    const win = windows.find(w => w.id === activeWindowId);
    return win ? getAppName(win.appId) : 'Finder';
  };

  return (
    <div 
      className="h-screen w-screen overflow-hidden bg-cover bg-center text-sm font-sans flex flex-col relative select-none transition-all duration-700 ease-in-out"
      style={{ backgroundImage: currentWallpaper }}
    >
      <TopBar 
        activeAppTitle={getActiveAppTitle()} 
        onOpenApp={openWindow}
        onOpenAchievements={() => openWindow(AppID.ACHIEVEMENTS)}
        onReset={handleSystemReset}
        hasUnreadAchievements={false} // Simple implementation: glow resets on click essentially
      />

      <div className="flex-1 relative overflow-hidden">
        <Desktop 
          files={files} 
          selectedIds={selectedDesktopIds} 
          onSelect={handleDesktopSelect} 
          onOpen={openFile}
        />

        <AnimatePresence>
          {windows.map(win => {
            const AppComponent = APP_COMPONENTS[win.appId];
            const file = win.contentId ? files[win.contentId] : null;

            // Determine initial path for Finder-based apps
            let initialPath = 'desktop';
            if (win.appId === AppID.TRASH) {
              initialPath = 'trash_bin';
            } else if (win.appId === AppID.FINDER) {
              initialPath = win.contentId || 'desktop';
            }

            return (
              <Window
                key={win.id}
                window={win}
                isActive={activeWindowId === win.id}
                onClose={closeWindow}
                onFocus={focusWindow}
                onMinimize={toggleMinimize}
                onMaximize={toggleMaximize}
                onResize={resizeWindow}
              >
                <AppComponent 
                  file={file} 
                  files={files} 
                  initialPath={initialPath}
                  onNavigate={(id: string) => {}}
                  onOpenFile={openFile}
                  onOpenApp={openWindow}
                  onInteraction={handleAppInteraction}

                  // Settings Props
                  currentWallpaper={currentWallpaper}
                  onWallpaperChange={setCurrentWallpaper}
                  screensaverEnabled={screensaverEnabled}
                  onScreensaverToggle={setScreensaverEnabled}
                  screensaverTimeout={screensaverTimeout}
                  onScreensaverTimeoutChange={setScreensaverTimeout}

                  // Achievements Props
                  unlocked={achievements}
                />
              </Window>
            );
          })}
        </AnimatePresence>
      </div>

      <Dock 
        openApps={windows.map(w => w.appId)} 
        onOpenApp={(appId) => openWindow(appId)}
      />

      <Notification 
        notification={notification} 
        onClose={() => setNotification(null)}
        onClick={() => {
          setNotification(null);
          openWindow(AppID.ACHIEVEMENTS);
        }}
      />

      {/* System Alert Modal */}
      <AnimatePresence>
        {alertConfig.isOpen && (
          <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/20 backdrop-blur-[2px]">
            <motion.div 
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              transition={{ type: "spring", stiffness: 400, damping: 25 }}
              className="bg-white/90 dark:bg-stone-800/90 backdrop-blur-xl border border-white/20 dark:border-white/10 shadow-2xl rounded-xl p-6 w-80 max-w-full text-center flex flex-col items-center gap-4"
            >
              <div className="w-12 h-12 bg-stone-100 dark:bg-stone-700 rounded-full flex items-center justify-center">
                 <AlertTriangle className="text-stone-500 dark:text-stone-300" size={24} />
              </div>
              <div className="flex-1">
                <h3 className="font-bold text-lg text-stone-900 dark:text-stone-100 mb-1">Access Denied</h3>
                <p className="text-stone-600 dark:text-stone-300 leading-relaxed">{alertConfig.message}</p>
              </div>
              <button 
                onClick={() => setAlertConfig(prev => ({ ...prev, isOpen: false }))}
                className="w-full py-2 bg-stone-800 hover:bg-stone-900 dark:bg-stone-200 dark:hover:bg-white text-white dark:text-stone-900 font-medium rounded-lg transition-colors"
              >
                OK
              </button>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {isScreensaverActive && (
          <Screensaver onWake={resetIdleTimer} />
        )}
      </AnimatePresence>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Wifi, Battery, Search, Command, Trophy } from 'lucide-react';
import { format } from 'date-fns';
import { AppID } from '../../types';

interface TopBarProps {
  activeAppTitle: string;
  onOpenApp: (id: AppID) => void;
  onOpenAchievements: () => void;
  onReset: () => void;
  hasUnreadAchievements: boolean;
}

const TopBar: React.FC<TopBarProps> = ({ activeAppTitle, onOpenApp, onOpenAchievements, onReset, hasUnreadAchievements }) => {
  const [time, setTime] = useState(new Date());
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
