import React, { useState, useEffect, useRef } from 'react';
import { Wifi, Battery, Search, Command, Trophy } from 'lucide-react';
import { format } from 'date-fns';
import { AppID } from '../../types';

interface TopBarProps {
  activeAppTitle: string;
  onOpenApp: (id: AppID) => void;
  onOpenAchievements: () => void;
  onReset: () => void;
  hasUnreadAchievements: boolean;
}

const TopBar: React.FC<TopBarProps> = ({ activeAppTitle, onOpenApp, onOpenAchievements, onReset, hasUnreadAchievements }) => {
  const [time, setTime] = useState(new Date());
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div 
      className="h-8 backdrop-blur-md flex items-center justify-between px-4 select-none text-sm font-medium relative z-[100] transition-colors duration-300"
      style={{
        background: 'var(--bg-bar)',
        borderBottom: 'var(--border-width) solid var(--border-color)',
        color: 'var(--text-color)',
        fontFamily: 'var(--font-family)',
      }}
    >
      {/* Left */}
      <div className="flex items-center gap-4">
        <div className="relative" ref={menuRef}>
          <div 
            className="font-bold flex items-center gap-1 text-lg px-2 py-1 -ml-2 rounded hover:bg-black/5 dark:hover:bg-white/10 cursor-pointer transition-colors"
            onClick={() => setIsMenuOpen(!isMenuOpen)}
          >
             <Command size={16} />
          </div>

          {/* Dropdown Menu */}
          {isMenuOpen && (
            <div 
              className="absolute top-full left-0 mt-1 w-56 backdrop-blur-xl rounded shadow-xl py-1 flex flex-col z-[200]"
              style={{
                background: 'var(--bg-window)',
                border: 'var(--border-width) solid var(--border-color)',
                color: 'var(--text-color)',
                fontFamily: 'var(--font-family)',
              }}
            >
              <div className="px-4 py-2 text-xs opacity-60">PortfolioOS v2.0</div>
              <div className="h-px bg-current opacity-10 my-1" />
              <button 
                className="text-left px-4 py-1.5 hover:bg-blue-500 hover:text-white transition-colors text-sm"
                onClick={() => {
                  onOpenApp(AppID.SYSTEM_PREFERENCES);
                  setIsMenuOpen(false);
                }}
              >
                System Preferences...
              </button>
              <div className="h-px bg-current opacity-10 my-1" />
              <button 
                className="text-left px-4 py-1.5 hover:bg-blue-500 hover:text-white transition-colors text-sm"
                onClick={() => {
                  setIsMenuOpen(false);
                  onReset();
                }}
              >
                Restart...
              </button>
              <button 
                className="text-left px-4 py-1.5 hover:bg-blue-500 hover:text-white transition-colors text-sm"
                onClick={() => {
                  setIsMenuOpen(false);
                }}
              >
                Lock Screen
              </button>
            </div>
          )}
        </div>

        <span className="font-bold">{activeAppTitle}</span>
        <div className="hidden sm:flex gap-4 font-normal opacity-80">
           <span>File</span>
           <span>Edit</span>
           <span>View</span>
           <span>Window</span>
           <span>Help</span>
        </div>
      </div>

      {/* Right */}
      <div className="flex items-center gap-4">
        <Search size={16} className="opacity-80" />

        <div 
          className="relative cursor-pointer opacity-80 hover:opacity-100 transition-opacity"
          onClick={onOpenAchievements}
        >
          <Trophy size={16} />
          {hasUnreadAchievements && (
            <span className="absolute -top-1 -right-1 w-2 h-2 bg-yellow-500 rounded-full animate-pulse shadow-sm" />
          )}
        </div>

        <div className="flex items-center gap-2 opacity-80">
           <span className="hidden sm:inline text-xs opacity-80">100%</span>
           <Battery size={18} />
        </div>
        <Wifi size={16} className="opacity-80" />
        <span className="w-20 text-right">{format(time, 'EEE MMM d HH:mm')}</span>
      </div>
    </div>
  );
};

export default TopBar;

import React, { useRef } from 'react';
import { FileSystemItem, FileType, AppID } from '../../types';
import { Folder, FileText, Image as ImageIcon, Trash2, Mail, Terminal, Gamepad2, FileCode } from 'lucide-react';

interface DesktopProps {
  files: Record<string, FileSystemItem>;
  selectedIds: string[];
  onSelect: (id: string, multi: boolean) => void;
  onOpen: (item: FileSystemItem) => void;
}

const Desktop: React.FC<DesktopProps> = ({ files, selectedIds, onSelect, onOpen }) => {
  const desktopItems = files['desktop'].children?.map(id => files[id]) || [];
  const containerRef = useRef<HTMLDivElement>(null);

  const getIcon = (item: FileSystemItem) => {
    // Custom App Icons
    if (item.appId === AppID.EMAIL) return <Mail className="w-12 h-12 text-stone-200 drop-shadow-md" />;
    if (item.appId === AppID.TERMINAL) return <Terminal className="w-12 h-12 text-gray-200 drop-shadow-md" />;
    if (item.appId === AppID.MINESWEEPER) return <Gamepad2 className="w-12 h-12 text-stone-200 drop-shadow-md" />;
    if (item.appId === AppID.TRASH) return <Trash2 className="w-12 h-12 text-stone-200 drop-shadow-md" />;

    // File Types
    if (item.type === FileType.FOLDER) return <Folder className="w-12 h-12 text-blue-300 fill-blue-300/20 drop-shadow-md" />;
    if (item.name.endsWith('.pdf')) return <FileText className="w-12 h-12 text-red-300 drop-shadow-md" />;
    if (item.name.endsWith('.png')) return <ImageIcon className="w-12 h-12 text-purple-300 drop-shadow-md" />;
    if (item.name.endsWith('.txt')) return <FileText className="w-12 h-12 text-gray-300 drop-shadow-md" />;

    return <FileCode className="w-12 h-12 text-gray-300" />;
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    if (e.target === containerRef.current) {
      onSelect('', false);
    }
  };

  return (
    <div 
      ref={containerRef}
      className="absolute inset-0 z-0 p-4 grid grid-flow-col grid-rows-[repeat(auto-fill,110px)] gap-2 content-start items-start justify-items-start"
      onPointerDown={handlePointerDown}
    >
      {desktopItems.map(item => {
         const isSelected = selectedIds.includes(item.id);
         return (
           <div
             key={item.id}
             className={`w-24 flex flex-col items-center justify-start gap-1 p-1 rounded-md border border-transparent transition-all duration-200 group
               ${isSelected ? 'bg-white/20 border-white/30 backdrop-blur-md shadow-sm' : 'hover:bg-white/10'}
             `}
             onPointerDown={(e) => {
               e.stopPropagation();
               onSelect(item.id, e.metaKey || e.ctrlKey);
             }}
             onDoubleClick={(e) => {
               e.stopPropagation();
               onOpen(item);
             }}
           >
             <div 
               className="transition-transform group-hover:scale-105 shrink-0"
               style={{ filter: 'var(--icon-filter)' }}
             >
               {getIcon(item)}
             </div>
             <span 
               className={`text-xs font-medium text-center px-2 py-0.5 rounded w-full break-words leading-tight
                 ${isSelected ? 'bg-blue-600 text-white' : 'text-white drop-shadow-md shadow-black'}
               `}
               style={{ 
                 textShadow: isSelected ? 'none' : '0 1px 2px rgba(0,0,0,0.8)',
                 fontFamily: 'var(--font-family)',
               }}
             >
               {item.name}
             </span>
           </div>
         );
      })}
    </div>
  );
};

export default Desktop;

