  isMinimized: boolean;
  isMaximized: boolean;
  zIndex: number;
  position: { x: number; y: number };
  size: { width: number; height: number };
}

export interface SystemState {
  windows: WindowState[];
  activeWindowId: string | null;
  files: Record<string, FileSystemItem>;
  clipboard: string | null;
